expanded_persona:
{
  "short_persona": {
    "persona": "A musicologist studying the correlation between visual acuity and musical performance"
  },
  "name": "Dr. Anika Sharma",
  "age": 34,
  "gender": "Woman",
  "sexual_orientation": "Heterosexual / Straight",
  "race": "South Asian (Indian heritage)",
  "nationality": "Indian-Canadian",
  "personality": {
    "primary_traits": [
      "curious",
      "analytical",
      "empathetic",
      "meticulous",
      "warm"
    ],
    "secondary_traits": [
      "perfectionist",
      "slightly reserved with strangers",
      "open-minded with new research ideas"
    ],
    "motivations": [
      "advancing interdisciplinary music research",
      "supporting accessibility in music performance",
      "contributing to academic communities worldwide"
    ],
    "values": [
      "precision in scholarship",
      "inclusivity",
      "lifelong learning",
      "artistic expression"
    ]
  },
  "degree": "Doctor of Philosophy (PhD) in Musicology with a minor in Cognitive Neuroscience",
  "school_or_work": {
    "current_position": "Assistant Professor of Musicology",
    "institution": "University of Toronto",
    "research_affiliation": "Collaborative Neuroscience & Music Perception Lab",
    "past_education": [
      {
        "degree": "Bachelor of Arts in Music Performance (Piano)",
        "institution": "Delhi University",
        "year_completed": 2012
      },
      {
        "degree": "Master of Arts in Ethnomusicology",
        "institution": "McGill University",
        "year_completed": 2015
      }
    ]
  },
  "languages_spoken": [
    "English (native-level fluency)",
    "Hindi (fluent)",
    "French (intermediate)"
  ],
  "location": {
    "current_city": "Toronto, Canada",
    "hometown": "New Delhi, India",
    "urban_or_rural": "Urban"
  },
  "socioeconomic_background": {
    "childhood_status": "Middle-class upbringing in India, with strong family emphasis on education and music",
    "current_class": "Upper-middle class, due to academic position and combined family income"
  },
  "hobbies_and_interests": [
    "Classical piano performance",
    "Attending art exhibitions",
    "Reading science and philosophy books",
    "Practicing yoga",
    "Traveling to music festivals"
  ],
  "technology_habits": {
    "devices_used": [
      "Laptop",
      "Smartphone",
      "Tablet"
    ],
    "research_tools": [
      "Statistical analysis software",
      "Audiovisual recording devices",
      "Eye-tracking systems"
    ],
    "social_media": [
      "LinkedIn",
      "ResearchGate",
      "Instagram for artistic projects"
    ]
  },
  "speaking_style_with_chatbot": {
    "tone": "Polite, professional, and warm; blends academic precision with a touch of friendly openness, ensuring clarity in communication while fostering collaborative exchange.",
    "formality": "Moderately formal in research-related discussions but can shift to semi-formal when exploring creative or personal topics related to music.",
    "pacing": "Measured and deliberate; she takes time to structure her thoughts and often pauses to refine questions, especially when discussing complex topics.",
    "vocabulary": "Advanced academic vocabulary with occasional use of technical terminology from musicology, neuroscience, and cognitive sciences, balanced with accessible language to ensure mutual understanding. Tends to provide specific context rather than vague queries, often using precise qualifiers such as 'empirical,' 'sensory perception,' or 'performance dynamics.'",
    "conversational_structure": "Sequential and logical, often starting with contextual background, followed by clear questions or hypotheses; tends to reference prior points made in the conversation to maintain thematic continuity."
  }
}

